use-key-basic.raw:
"use client";

import { KeyboardProvider, useKey } from "@diffgazer/keys";
import { useState } from "react";

function Counter() {
  const [count, setCount] = useState(0);

  useKey("ArrowUp", () => setCount((c) => c + 1));
  useKey("ArrowDown", () => setCount((c) => c - 1));
  useKey("Escape", () => setCount(0));

  return (
    <div>
      <p style={{ fontSize: 24, fontFamily: "ui-monospace, monospace", textAlign: "center" }}>
        {count}
      </p>
      <p>ArrowUp increments, ArrowDown decrements, Escape resets.</p>
    </div>
  );
}

export default function UseKeyBasic() {
  return (
    <KeyboardProvider>
      <Counter />
    </KeyboardProvider>
  );
}

use-key-map.raw:
"use client";

import { KeyboardProvider, useKey } from "@diffgazer/keys";
import { useState } from "react";

function TextFormatter() {
  const [style, setStyle] = useState<"normal" | "bold" | "italic" | "underline">("normal");

  useKey(
    {
      "ctrl+b": () => setStyle("bold"),
      "ctrl+i": () => setStyle("italic"),
      "ctrl+u": () => setStyle("underline"),
      Escape: () => setStyle("normal"),
    },
    { preventDefault: true },
  );

  return (
    <div>
      <p
        style={{
          fontWeight: style === "bold" ? 700 : 400,
          fontStyle: style === "italic" ? "italic" : "normal",
          textDecoration: style === "underline" ? "underline" : "none",
        }}
      >
        The quick brown fox jumps over the lazy dog.
      </p>
      <p>Active: {style}</p>
      <p>Ctrl+B bold, Ctrl+I italic, Ctrl+U underline, Esc reset.</p>
    </div>
  );
}

export default function UseKeyMap() {
  return (
    <KeyboardProvider>
      <TextFormatter />
    </KeyboardProvider>
  );
}

use-key-scoped.raw:
"use client";

import { KeyboardProvider, useKey } from "@diffgazer/keys";
import { useRef, useState } from "react";

function Editor() {
  const [saved, setSaved] = useState(0);
  const cardRef = useRef<HTMLDivElement>(null);

  // focusWithinOnly + containerRef: the shortcut only fires while focus is
  // inside this card, so two editors on one page do not collide.
  useKey("ctrl+s", () => setSaved((n) => n + 1), {
    containerRef: cardRef,
    focusWithinOnly: true,
    preventDefault: true,
    allowInInput: true,
  });

  return (
    <div ref={cardRef} style={{ padding: 12, border: "1px solid currentColor" }}>
      <p>Click into the textarea, then press Ctrl+S. Saves: {saved}</p>
      <textarea
        aria-label="Note"
        rows={2}
        style={{ width: "100%" }}
        defaultValue="Focus me, then Ctrl+S"
      />
    </div>
  );
}

export default function UseKeyScoped() {
  return (
    <KeyboardProvider>
      <div style={{ display: "grid", gap: 8 }}>
        <Editor />
        <Editor />
        <p>Each card owns its own Ctrl+S; the binding is inert unless its card has focus.</p>
      </div>
    </KeyboardProvider>
  );
}
